const items = $input.all();
const statistici = items.map(item => item.json);

const total = statistici.length;
const note = {};
statistici.forEach(item => {
  note[item.nota] = (note[item.nota] || 0) + 1;
});

const notaPref = Object.keys(note).reduce((a, b) => note[a] > note[b] ? a : b, '');

const raport = `
📊 RAPORT ZILNIC ULBS Coach
Data: ${new Date().toLocaleDateString('ro-RO')}

Total intrebari: ${total}
Nota preferata: ${notaPref}

Distributie note:
${Object.entries(note).map(([nota, count]) => `  Nota ${nota}: ${count} intrebari`).join('\n')}

Ultimele intrebari:
${statistici.slice(0, 5).map(s => `  - ${s.intrebare} (Nota ${s.nota})`).join('\n')}
`;

return [{ json: { raport, total, notaPref } }];
